type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

// Hardcoded quotes for the only two scenarios exercised so far.
// These will be replaced by real calculation as more tests drive the implementation.
const FEE_ONLY_QUOTE = 5;
const SINGLE_PLAIN_SWORD_QUOTE = 115;

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  const results = scenario.steps.map((step) => ({
    premium: step.items.length === 0 ? FEE_ONLY_QUOTE : SINGLE_PLAIN_SWORD_QUOTE,
  }));
  return { results };
};
